  Def(Variable l, Type t, AST r) { lhs = l; lhsType = t; rhs = r; }
  public Variable lhs() { return lhs; }
  public Type lhsType() { return lhsType; }
  public AST rhs() { return rhs; }

  public String toString() { return lhs + ": " + lhsType + " := " + rhs + ";"; }
}

/** Dummy class containing an improved toString method for arrays. */
class ToString {

  public static String toString(Object[] a, String s) {
    StringBuffer result = new StringBuffer();
    for (int i = 0; i < a.length; i++) {
      if (i > 0) result.append(s);
      Object elt = a[i];
      String eltString = (elt instanceof Object[]) ?
        toString((Object[]) elt, s) : elt.toString();
      result.append(eltString);
    }
    return result.toString();
  }
}

import java.io.FileReader;
import java.io.IOException;
import java.io.Reader;
import java.util.ArrayList;
import java.util.HashMap;

/** Class that represented parsing errors. */
class ParseException extends RuntimeException {
  ParseException(String s) { super(s); }
  ParseException(Throwable t) { super(t); }
}

class Parser {
  private Lexer in;
  private String source;
  private int pos;
  private Lexeme lookahead;
  private HashMap<String, Variable> vars = new HashMap<String, Variable>();

  Parser(Lexer i) {
    in = i;
    source = slurp(i.rdr);
    pos = 0;
  }

  Parser(Reader inputStream) { this(new Lexer(inputStream)); }

  Parser(String fileName) throws IOException { this(new FileReader(fileName)); }

  Lexer lexer() { return in; }

  public void initParser() { }

  public AST parse() throws ParseException {
    reset();
    AST prog = parseExp();
    expect(LexemeKind.EOF);
    return prog;
  }

  public AST parseAndCheck() throws ParseException {
    AST prog = parse();
    prog.accept(CheckVisitor.INITIAL);
    return prog;
  }

  private void reset() {
    pos = 0;
    lookahead = null;
  }

  private String slurp(Reader rdr) {
    try {
      StringBuilder sb = new StringBuilder();
      char[] buf = new char[1024];
      int n;
      while ((n = rdr.read(buf)) != -1) sb.append(buf, 0, n);
      return sb.toString();
    } catch (IOException e) {
      throw new ParseException(e);
    }
  }

  private AST parseExp() {
    if (acceptKeyword("if")) return parseIf();
    if (acceptKeyword("let")) return parseLet();
    if (acceptKeyword("map")) return parseMap();
    if (acceptSymbol("{")) return parseBlock();

    AST exp = parseTerm();
    while (isBinOp(peek())) {
      BinOp op = readBinOp(next());
      AST rhs = parseTerm();
      exp = new BinOpApp(op, exp, rhs);
    }
    return exp;
  }

  private AST parseTerm() {
    Lexeme tok = peek();
    if (isUnOp(tok)) {
      UnOp op = readUnOp(next());
      return new UnOpApp(op, parseTerm());
    }
    return parsePostfix();
  }

  private AST parsePostfix() {
    Lexeme tok = peek();
    if (tok.kind == LexemeKind.PRIM) {
      AST prim = parsePrim();
      expectSymbol("(");
      return new App(prim, parseArgs());
    }

    AST factor = parseFactor();
    while (acceptSymbol("(")) {
      factor = new App(factor, parseArgs());
    }
    return factor;
  }

  private AST parseFactor() {
    Lexeme tok = peek();
    if (acceptSymbol("(")) {
      AST exp = parseExp();
      expectSymbol(")");
      return exp;
    }
    if (tok.kind == LexemeKind.INT) {
      next();
      return new IntConstant(Integer.parseInt(tok.text));
    }
    if (tok.kind == LexemeKind.BOOL) {
      next();
      return tok.text.equals("true") ? BoolConstant.TRUE : BoolConstant.FALSE;
    }
    if (acceptKeyword("empty")) {
      expectSymbol(":");
      return new EmptyConstant(parseType());
    }
    if (tok.kind == LexemeKind.ID) {
      next();
      return internVar(tok.text);
    }
    throw error(tok, "expression");
  }

  private AST parseIf() {
    AST test = parseExp();
    expectKeyword("then");
    AST conseq = parseExp();
    expectKeyword("else");
    AST alt = parseExp();
    return new If(test, conseq, alt);
  }

  private AST parseLet() {
    ArrayList<Def> defs = new ArrayList<Def>();
    do {
      defs.add(parseDef());
    } while (!acceptKeyword("in"));
    return new Let(defs.toArray(new Def[0]), parseExp());
  }

  private AST parseMap() {
    ArrayList<Variable> params = new ArrayList<Variable>();
    ArrayList<Type> types = new ArrayList<Type>();
    if (!acceptKeyword("to")) {
      do {
        TypedVar tv = parseTypedVar();
        params.add(tv.var);
        types.add(tv.type);
      } while (acceptSymbol(","));
      expectKeyword("to");
    }
    return new Map(params.toArray(new Variable[0]), types.toArray(new Type[0]), parseExp());
  }

  private AST parseBlock() {
    ArrayList<AST> exps = new ArrayList<AST>();
    if (acceptSymbol("}")) throw new ParseException("Illegal empty block");
    exps.add(parseExp());
    while (acceptSymbol(";")) {
      if (acceptSymbol("}")) return new Block(exps.toArray(new AST[0]));
      exps.add(parseExp());
    }
    expectSymbol("}");
    return new Block(exps.toArray(new AST[0]));
  }

  private AST[] parseArgs() {
    ArrayList<AST> args = new ArrayList<AST>();
    if (!acceptSymbol(")")) {
      do {
        args.add(parseExp());
      } while (acceptSymbol(","));
      expectSymbol(")");
    }
    return args.toArray(new AST[0]);
  }

  private Def parseDef() {
    TypedVar tv = parseTypedVar();
    expectSymbol(":=");
    AST rhs = parseExp();
    expectSymbol(";");
    return new Def(tv.var, tv.type, rhs);
  }

  private TypedVar parseTypedVar() {
    Lexeme id = expect(LexemeKind.ID);
    expectSymbol(":");
    return new TypedVar(internVar(id.text), parseType());
  }

  private Type parseType() {
    Lexeme tok = peek();
    if (acceptKeyword("unit")) return UnitType.ONLY;
    if (acceptKeyword("int")) return IntType.ONLY;
    if (acceptKeyword("bool")) return BoolType.ONLY;
    if (acceptKeyword("list")) return new ListType(parseType());
    if (acceptKeyword("ref")) return new RefType(parseType());
    if (acceptSymbol("(")) {
      ArrayList<Type> params = new ArrayList<Type>();
      if (!acceptSymbol("->")) {
        if (!acceptSymbol(")")) {
          do {
            params.add(parseType());
          } while (acceptSymbol(","));
          expectSymbol("->");
          Type result = parseType();
          expectSymbol(")");
          return new FunType(params.toArray(new Type[0]), result);
        }
        expectSymbol("->");
      }
      Type result = parseType();
      expectSymbol(")");
      return new FunType(new Type[0], result);
    }
    throw error(tok, "type");
  }

  private PrimFun parsePrim() {
    Lexeme tok = next();
    if (tok.text.equals("empty?")) return EmptyPPrim.ONLY;
    if (tok.text.equals("cons?")) return ConsPPrim.ONLY;
    if (tok.text.equals("cons")) return ConsPrim.ONLY;
    if (tok.text.equals("first")) return FirstPrim.ONLY;
    if (tok.text.equals("rest")) return RestPrim.ONLY;
    throw error(tok, "primitive");
  }

  private Variable internVar(String name) {
    Variable v = vars.get(name);
    if (v == null) {
      v = new Variable(name);
      vars.put(name, v);
    }
    return v;
  }

  private boolean isUnOp(Lexeme tok) {
    return tok.kind == LexemeKind.SYMBOL && (tok.text.equals("+") || tok.text.equals("-") || tok.text.equals("~")
      || tok.text.equals("!")) || tok.kind == LexemeKind.KEYWORD && tok.text.equals("ref");
  }

  private boolean isBinOp(Lexeme tok) {
    return tok.kind == LexemeKind.SYMBOL && (
      tok.text.equals("+") || tok.text.equals("-") || tok.text.equals("*") || tok.text.equals("/")
        || tok.text.equals("=") || tok.text.equals("!=") || tok.text.equals("<") || tok.text.equals(">")
        || tok.text.equals("<=") || tok.text.equals(">=") || tok.text.equals("&") || tok.text.equals("|")
        || tok.text.equals("<-"));
  }

  private UnOp readUnOp(Lexeme tok) {
    if (tok.text.equals("+")) return UnOpPlus.ONLY;
    if (tok.text.equals("-")) return UnOpMinus.ONLY;
    if (tok.text.equals("~")) return OpTilde.ONLY;
    if (tok.text.equals("!")) return OpBang.ONLY;
    return OpRef.ONLY;
  }

  private BinOp readBinOp(Lexeme tok) {
    if (tok.text.equals("+")) return BinOpPlus.ONLY;
    if (tok.text.equals("-")) return BinOpMinus.ONLY;
    if (tok.text.equals("*")) return OpTimes.ONLY;
    if (tok.text.equals("/")) return OpDivide.ONLY;
    if (tok.text.equals("=")) return OpEquals.ONLY;
    if (tok.text.equals("!=")) return OpNotEquals.ONLY;
    if (tok.text.equals("<")) return OpLessThan.ONLY;
    if (tok.text.equals(">")) return OpGreaterThan.ONLY;
    if (tok.text.equals("<=")) return OpLessThanEquals.ONLY;
    if (tok.text.equals(">=")) return OpGreaterThanEquals.ONLY;
    if (tok.text.equals("&")) return OpAnd.ONLY;
    if (tok.text.equals("|")) return OpOr.ONLY;
    return OpGets.ONLY;
  }

  private boolean acceptKeyword(String s) {
    if (peek().kind == LexemeKind.KEYWORD && peek().text.equals(s)) {
      next();
      return true;
    }
    return false;
  }

  private void expectKeyword(String s) {
    Lexeme tok = next();
    if (tok.kind != LexemeKind.KEYWORD || !tok.text.equals(s)) throw error(tok, "`" + s + "'");
  }

  private boolean acceptSymbol(String s) {
    if (peek().kind == LexemeKind.SYMBOL && peek().text.equals(s)) {
      next();
      return true;
    }
    return false;
  }

  private void expectSymbol(String s) {
    Lexeme tok = next();
    if (tok.kind != LexemeKind.SYMBOL || !tok.text.equals(s)) throw error(tok, "`" + s + "'");
  }

  private Lexeme expect(LexemeKind kind) {
    Lexeme tok = next();
    if (tok.kind != kind) throw error(tok, kind.toString().toLowerCase());
    return tok;
  }

  private Lexeme peek() {
    if (lookahead == null) lookahead = scan();
    return lookahead;
  }

  private Lexeme next() {
    Lexeme tok = peek();
    lookahead = null;
    return tok;
  }

  private ParseException error(Lexeme found, String expected) {
    return new ParseException("Token `" + found.text + "' appears where " + expected + " was expected");
  }

  private void skipSpace() {
    while (pos < source.length()) {
      char c = source.charAt(pos);
      if (Character.isWhitespace(c)) {
        pos++;
      } else if (c == '/' && pos + 1 < source.length() && source.charAt(pos + 1) == '/') {
        pos += 2;
        while (pos < source.length() && source.charAt(pos) != '\n') pos++;
      } else {
        break;
      }
    }
  }

  private Lexeme scan() {
    skipSpace();
    if (pos >= source.length()) return new Lexeme(LexemeKind.EOF, "*EOF*");
    char c = source.charAt(pos);
    if (Character.isDigit(c)) {
      int start = pos++;
      while (pos < source.length() && Character.isDigit(source.charAt(pos))) pos++;
      return new Lexeme(LexemeKind.INT, source.substring(start, pos));
    }
    if (Character.isLetter(c) || c == '_') {
      int start = pos++;
      while (pos < source.length()) {
        char ch = source.charAt(pos);
        if (Character.isLetterOrDigit(ch) || ch == '_' || ch == '?') pos++;
        else break;
      }
      String word = source.substring(start, pos);
      if (word.equals("true") || word.equals("false")) return new Lexeme(LexemeKind.BOOL, word);
      if (isKeyword(word)) return new Lexeme(LexemeKind.KEYWORD, word);
      if (isPrim(word)) return new Lexeme(LexemeKind.PRIM, word);
      return new Lexeme(LexemeKind.ID, word);
    }
    if (pos + 1 < source.length()) {
      String two = source.substring(pos, pos + 2);
      if (two.equals(":=") || two.equals("!=") || two.equals("<=") || two.equals(">=") || two.equals("<-")
        || two.equals("->")) {
        pos += 2;
        return new Lexeme(LexemeKind.SYMBOL, two);
      }
    }
    pos++;
    if ("(){};,:+-*/=<>~!&|".indexOf(c) >= 0) return new Lexeme(LexemeKind.SYMBOL, String.valueOf(c));
    throw new ParseException("'" + c + "' is not a legal token");
  }

  private boolean isKeyword(String word) {
    return word.equals("if") || word.equals("then") || word.equals("else") || word.equals("let")
      || word.equals("in") || word.equals("map") || word.equals("to") || word.equals("empty")
      || word.equals("unit") || word.equals("int") || word.equals("bool") || word.equals("list")
      || word.equals("ref");
  }

  private boolean isPrim(String word) {
    return word.equals("empty?") || word.equals("cons?") || word.equals("cons")
      || word.equals("first") || word.equals("rest");
  }

  private static final class TypedVar {
    private Variable var;
    private Type type;

    private TypedVar(Variable v, Type t) { var = v; type = t; }
  }

  private static final class Lexeme {
    private LexemeKind kind;
    private String text;

    private Lexeme(LexemeKind k, String t) { kind = k; text = t; }
  }

  private enum LexemeKind {
    INT, BOOL, ID, KEYWORD, PRIM, SYMBOL, EOF
  }
}

import java.io.StringReader;
import junit.framework.TestCase;

public class Assign5AgentTest extends TestCase {

  private JamVal eager(String program) {
    return new Interpreter(new StringReader(program)).eagerEval();
  }

  private JamVal lazy(String program) {
    return new Interpreter(new StringReader(program)).lazyEval();
  }

  public void testReferenceTypingAndEvaluation() {
    String program = "let x: ref int := ref 1; in {x <- 2; ! x}";
    assertEquals("2", eager(program).toString());
    assertEquals("2", lazy(program).toString());
  }

  public void testPrimitiveCannotBeUsedAsValue() {
    try {
      eager("let f: (int, list int -> list int) := cons; in f(1, empty: int)");
      fail("expected ParseException");
    } catch (ParseException e) {
      assertTrue(e.getMessage().contains("("));
    }
  }

  public void testTypeMismatchInDefinition() {
    try {
      eager("let x: bool := 1; in x");
      fail("expected TypeException");
    } catch (TypeException e) {
      assertTrue(e.getMessage().contains("wrong type"));
    }
  }

  public void testEmptyTypeMustBeAListType() {
    assertEquals("()", eager("empty: int").toString());
  }

  public void testZeroArgumentFunction() {
    String program = "let f: (-> int) := map to 5; in f()";
    assertEquals("5", eager(program).toString());
    assertEquals("5", lazy(program).toString());
  }
}

