+  private void skipSpace() {
+    while (pos < source.length()) {
+      char c = source.charAt(pos);
+      if (Character.isWhitespace(c)) {
+        pos++;
+      } else if (c == '/' && pos + 1 < source.length() && source.charAt(pos + 1) == '/') {
+        pos += 2;
+        while (pos < source.length() && source.charAt(pos) != '\n') pos++;
+      } else {
+        break;
+      }
+    }
+  }
+
+  private Lexeme scan() {
+    skipSpace();
+    if (pos >= source.length()) return new Lexeme(LexemeKind.EOF, "*EOF*");
+    char c = source.charAt(pos);
+    if (Character.isDigit(c)) {
+      int start = pos++;
+      while (pos < source.length() && Character.isDigit(source.charAt(pos))) pos++;
+      return new Lexeme(LexemeKind.INT, source.substring(start, pos));
+    }
+    if (Character.isLetter(c) || c == '_') {
+      int start = pos++;
+      while (pos < source.length()) {
+        char ch = source.charAt(pos);
+        if (Character.isLetterOrDigit(ch) || ch == '_' || ch == '?') pos++;
+        else break;
+      }
+      String word = source.substring(start, pos);
+      if (word.equals("true") || word.equals("false")) return new Lexeme(LexemeKind.BOOL, word);
+      if (isKeyword(word)) return new Lexeme(LexemeKind.KEYWORD, word);
+      if (isPrim(word)) return new Lexeme(LexemeKind.PRIM, word);
+      return new Lexeme(LexemeKind.ID, word);
+    }
+    if (pos + 1 < source.length()) {
+      String two = source.substring(pos, pos + 2);
+      if (two.equals(":=") || two.equals("!=") || two.equals("<=") || two.equals(">=") || two.equals("<-")
+        || two.equals("->")) {
+        pos += 2;
+        return new Lexeme(LexemeKind.SYMBOL, two);
+      }
+    }
+    pos++;
+    if ("(){};,:+-*/=<>~!&|".indexOf(c) >= 0) return new Lexeme(LexemeKind.SYMBOL, String.valueOf(c));
+    throw new ParseException("'" + c + "' is not a legal token");
+  }
+
+  private boolean isKeyword(String word) {
+    return word.equals("if") || word.equals("then") || word.equals("else") || word.equals("let")
+      || word.equals("in") || word.equals("map") || word.equals("to") || word.equals("empty")
+      || word.equals("unit") || word.equals("int") || word.equals("bool") || word.equals("list")
+      || word.equals("ref");
+  }
+
+  private boolean isPrim(String word) {
+    return word.equals("empty?") || word.equals("cons?") || word.equals("cons")
+      || word.equals("first") || word.equals("rest");
+  }
+
+  private static final class TypedVar {
+    private Variable var;
+    private Type type;
+
+    private TypedVar(Variable v, Type t) { var = v; type = t; }
+  }
+
+  private static final class Lexeme {
+    private LexemeKind kind;
+    private String text;
+
+    private Lexeme(LexemeKind k, String t) { kind = k; text = t; }
+  }
+
+  private enum LexemeKind {
+    INT, BOOL, ID, KEYWORD, PRIM, SYMBOL, EOF
+  }
+}
